import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Authentication page. Since Firebase has been removed, this page
 * prompts the user for their name and stores it in localStorage.
 * Once a name is provided, the user is considered "logged in" and
 * redirected to the main application. If the user is already
 * authenticated (a valid auth object exists in localStorage), they
 * will be redirected immediately without seeing this form.
 */
export const Auth = () => {
  const [nameInput, setNameInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { isAuth } = useAuth();

  // Redirect authenticated users to the home page
  useEffect(() => {
    if (isAuth) {
      navigate('/app');
    }
  }, [isAuth, navigate]);

  const handleLogin = () => {
    const trimmedName = nameInput.trim();
    setError('');
    if (!trimmedName) {
      setError('Please enter your name');
      return;
    }
    setIsLoading(true);
    setTimeout(() => {
      const authInfo = {
        name: trimmedName,
        userID: Date.now().toString(),
        photo: null,
        isAuth: true,
      };
      localStorage.setItem('auth', JSON.stringify(authInfo));
      navigate('/app');
    }, 300);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && nameInput.trim()) {
      handleLogin();
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 bg-gradient-to-br from-slate-50 via-blue-50 to-slate-100">
      {/* Subtle decorative elements */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-0 right-0 w-96 h-96 bg-blue-200/30 rounded-full blur-3xl -mr-48 -mt-48"></div>
        <div className="absolute bottom-0 left-0 w-96 h-96 bg-blue-200/20 rounded-full blur-3xl -ml-48 -mb-48"></div>
      </div>

      <div className="w-full max-w-sm relative z-10">
        {/* Card */}
        <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-blue-100/50">
          {/* Header with gradient accent */}
          <div className="h-1 bg-gradient-to-r from-blue-500 via-blue-400 to-blue-500"></div>

          <div className="px-8 pt-12 pb-8">
            {/* Logo */}
            <div className="flex justify-center mb-6">
              <div className="w-16 h-16 rounded-xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-3xl shadow-lg">
                💰
              </div>
            </div>

            {/* Header text */}
            <div className="text-center mb-8">
              <h1 className="text-3xl font-bold text-gray-900 mb-2">Budget Buddy</h1>
              <p className="text-gray-600 text-sm">Take control of your finances</p>
            </div>

            {/* Form */}
            <div className="space-y-5">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Your Name
                </label>
                <input
                  type="text"
                  placeholder="John Doe"
                  value={nameInput}
                  onChange={(e) => {
                    setNameInput(e.target.value);
                    setError('');
                  }}
                  onKeyPress={handleKeyPress}
                  disabled={isLoading}
                  className="w-full px-4 py-3 rounded-lg border-2 border-gray-200 focus:border-blue-500 focus:outline-none transition-all duration-200 bg-gray-50 focus:bg-white text-gray-900 placeholder-gray-400 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                />
                {error && (
                  <p className="text-red-500 text-sm mt-2 font-medium">{error}</p>
                )}
              </div>

              <button
                onClick={handleLogin}
                disabled={isLoading || !nameInput.trim()}
                className="w-full bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 disabled:from-gray-400 disabled:to-gray-500 text-white font-semibold py-3 px-4 rounded-lg transition-all duration-200 transform hover:scale-105 hover:shadow-lg active:scale-95 disabled:opacity-60 disabled:cursor-not-allowed disabled:transform-none shadow-md"
              >
                {isLoading ? 'Signing in...' : 'Sign In'}
              </button>
            </div>

            {/* Divider */}
            <div className="my-6 flex items-center gap-3">
              <div className="flex-1 h-px bg-gray-200"></div>
              <span className="text-xs text-gray-500 font-medium">OR</span>
              <div className="flex-1 h-px bg-gray-200"></div>
            </div>

            {/* Features */}
            <div className="space-y-3">
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <span className="text-blue-500 font-bold">✓</span>
                <span>Track expenses instantly</span>
              </div>
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <span className="text-blue-500 font-bold">✓</span>
                <span>Visualize your spending</span>
              </div>
              <div className="flex items-center gap-3 text-sm text-gray-700">
                <span className="text-blue-500 font-bold">✓</span>
                <span>100% private & offline</span>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="px-8 py-4 bg-gradient-to-r from-blue-50 to-slate-50 border-t border-blue-100/50">
            <p className="text-center text-xs text-gray-600">
              No account needed • Data saved locally
            </p>
          </div>
        </div>

        {/* Footer text */}
        <p className="text-center text-sm text-gray-600 mt-6">
          Start managing your budget in seconds ✨
        </p>
      </div>
    </div>
  );
};
